		fmt.Fprintf(os.Stderr, "got-patch: unexpected .dynsym entsize=%d\n", dynsym.Entsize)
		os.Exit(1)
	}
	if dynsym.Off+dynsym.Size > uint64(len(in)) || dynstr.Off+dynstr.Size > uint64(len(in)) {
		fmt.Fprintf(os.Stderr, "got-patch: dynsym/dynstr out of range\n")
		os.Exit(1)
	}
	dynstrBytes := in[dynstr.Off : dynstr.Off+dynstr.Size]

	nSyms := int(dynsym.Size / dynsym.Entsize)
