		if err := readAt(in, off, &s); err != nil {
			fmt.Fprintf(os.Stderr, "got-patch: read dynsym[%d]: %v\n", i, err)
			os.Exit(1)
		}
		symName[i] = cStringFrom(dynstrBytes, s.Name)
	}

	mallocIdx := -1
	wrapperIdx := -1
	for i, n := range symName {
		if n == "malloc" {
			mallocIdx = i
		}
		if n == wrapper {
			wrapperIdx = i
		}
	}
	if wrapperIdx < 0 {
		fmt.Fprintf(os.Stderr, "got-patch: wrapper symbol not found in .dynsym: %q\n", wrapper)
		os.Exit(1)
	}
	if mallocIdx < 0 {
		fmt.Fprintf(os.Stderr, "got-patch: target symbol not found in .dynsym: %q\n", "malloc")
		os.Exit(1)
	}

	out := make([]byte, len(in))
	copy(out, in)

	patched := 0
	for si, sh := range shdrs {
		if sh.Type != shtRela {
			continue
		}
		if sh.Entsize == 0 {
			continue
		}
		if sh.Entsize != uint64(binary.Size(rela64{})) {
			// Only support standard ELF64 Rela entries.
			continue
		}
		if sh.Off+sh.Size > uint64(len(in)) {
			fmt.Fprintf(os.Stderr, "got-patch: relocation section %q out of range\n", secName(si))
			os.Exit(1)
		}
		n := int(sh.Size / sh.Entsize)
		for i := 0; i < n; i++ {
			entryOff := sh.Off + uint64(i)*sh.Entsize
			var r rela64
			if err := readAt(in, entryOff, &r); err != nil {
				fmt.Fprintf(os.Stderr, "got-patch: read rela %q[%d]: %v\n", secName(si), i, err)
				os.Exit(1)
			}
			sym := int(elf64RSym(r.Info))
			typ := elf64RType(r.Info)
			if sym != mallocIdx {
				continue
			}
			newInfo := elf64RInfo(uint32(wrapperIdx), typ)
			if newInfo == r.Info {
				continue
			}
			// r_info field is 8 bytes at offset +8 within Elf64_Rela
			if err := writeUint64At(out, entryOff+8, newInfo); err != nil {
				fmt.Fprintf(os.Stderr, "got-patch: write patched r_info: %v\n", err)
				os.Exit(1)
			}
			patched++
			fmt.Printf("patched relocation section=%s index=%d r_offset=0x%x r_type=%d: %s -> %s\n",
				secName(si), i, r.Off, typ, "malloc", wrapper)
		}
	}

	if patched == 0 {
		msg := fmt.Sprintf("got-patch: no applicable relocations found targeting %q (searched SHT_RELA sections); nothing patched", "malloc")
		fmt.Fprintln(os.Stderr, msg)
		os.Exit(1)
	}

	// Sanity: first 64 bytes must match exactly.
	if !bytes.Equal(in[:64], out[:64]) {
		fmt.Fprintf(os.Stderr, "got-patch: internal error: ELF header prefix (first 64 bytes) changed\n")
		os.Exit(1)
	}

	if err := writeFile0755(outPath, out); err != nil {
		fmt.Fprintf(os.Stderr, "got-patch: write output: %v\n", err)
		os.Exit(1)
	}
	fmt.Fprintf(os.Stderr, "got-patch: success: patched %d relocation(s); dynsym[%d]=%q -> dynsym[%d]=%q (dynsym section index %d)\n",
