func writeFile0755(path string, data []byte) error {
	// Write to temp then rename.
	tmp := path + ".tmp"
	_ = os.Remove(tmp)
	if err := os.WriteFile(tmp, data, 0o755); err != nil {
		return err
	}
	if err := os.Rename(tmp, path); err != nil {
		_ = os.Remove(tmp)
		return err
	}
	// Ensure mode even if umask interfered on some systems.
	if err := os.Chmod(path, 0o755); err != nil {
		return err
	}
	return nil
}

