		fmt.Fprintf(os.Stderr, "got-patch: write output: %v\n", err)
		os.Exit(1)
	}
	fmt.Fprintf(os.Stderr, "got-patch: success: patched %d relocation(s); dynsym[%d]=%q -> dynsym[%d]=%q (dynsym section index %d)\n",
		patched, mallocIdx, "malloc", wrapperIdx, wrapper, dynsymIdx)
}

func writeFile0755(path string, data []byte) error {
	// Write to temp then rename.
	tmp := path + ".tmp"
	_ = os.Remove(tmp)
	if err := os.WriteFile(tmp, data, 0o755); err != nil {
		return err
	}
	if err := os.Rename(tmp, path); err != nil {
		_ = os.Remove(tmp)
		return err
	}
	// Ensure mode even if umask interfered on some systems.
	if err := os.Chmod(path, 0o755); err != nil {
		return err
	}
	return nil
}

